const MOV_W_OPC_MOVZ: u32 = 0b10;
const MOV_W_OPC_MOVN: u32 = 0b00;

// ── Byte-level readers ────────────────────────────────────────────────

fn u16_at(mem: &[u8], off: usize) -> u16 {
    u16::from_le_bytes(mem[off..off + 2].try_into().unwrap())
}
fn u32_at(mem: &[u8], off: usize) -> u32 {
    u32::from_le_bytes(mem[off..off + 4].try_into().unwrap())
}
fn u64_at(mem: &[u8], off: usize) -> u64 {
    u64::from_le_bytes(mem[off..off + 8].try_into().unwrap())
}

// ── Instruction-field decoders ────────────────────────────────────────

/// Sign-extend the lowest `width` bits of `raw` to i32.
fn sign_ext(raw: u32, width: u32) -> i32 {
    let sh = 32 - width;
    ((raw << sh) as i32) >> sh
}

fn dec_imm14(insn: u32) -> i32 {
    sign_ext((insn >> 5) & 0x3FFF, 14)
}
fn dec_imm19(insn: u32) -> i32 {
    sign_ext((insn >> 5) & 0x007F_FFFF, 19)
}
fn dec_imm26(insn: u32) -> i32 {
    sign_ext(insn & 0x03FF_FFFF, 26)
}
fn dec_imm12(insn: u32) -> u32 {
    (insn >> 10) & 0xFFF
}
fn dec_movw(insn: u32) -> u16 {
    ((insn >> 5) & 0xFFFF) as u16
}

fn dec_imm21_adr(insn: u32) -> i32 {
    let lo = (insn >> 29) & 0x3;
    let hi = (insn >> 5) & 0x0007_FFFF;
    sign_ext((hi << 2) | lo, 21)
}

fn mov_w_opc(insn: u32) -> u32 {
    (insn >> 29) & 0x3
}

// ── Skeleton instruction words ────────────────────────────────────────

// LDR  X0, #0           → 0x5800_0000
const LDR_LIT: u32 = 0x5800_0000;
// ADR  X1, #0           → 0x0000_0001
const ADR: u32 = 0x0000_0001;
// ADRP X0, #0           → 0x9000_0000
const ADRP: u32 = 0x9000_0000;
// ADD  X0, X1, #0       → 0x9100_0020
const ADD: u32 = 0x9100_0020;
// TBZ  X0, #0, #0       → 0x3600_0000
const TBZ: u32 = 0x3600_0000;
// B.EQ #0               → 0x5400_0000
const BEQ: u32 = 0x5400_0000;
// B    #0               → 0x1400_0000
const B: u32 = 0x1400_0000;
// BL   #0               → 0x9400_0000
const BL: u32 = 0x9400_0000;
// MOVZ X0, #0           → 0xD280_0000
const MOVZ: u32 = 0xD280_0000;

/// Return a 4-byte buffer pre-loaded with an instruction word.
fn insn_buf(insn: u32) -> [u8; 4] {
    insn.to_le_bytes()
}

