// get_bytes_mut / get_bytes
// ═══════════════════════════════════════════════════════════════════════

#[test]
fn get_bytes_mut_ok() {
    let mut mem = [1u8, 2, 3, 4, 5, 6, 7, 8];
    let arr: &mut [u8; 4] = get_bytes_mut(&mut mem, 2).unwrap();
    assert_eq!(*arr, [3, 4, 5, 6]);
}

#[test]
fn get_bytes_mut_invalid_offset() {
    let mut mem = [0u8; 4];
    assert_eq!(
        get_bytes_mut::<4>(&mut mem, 5),
        Err(Rel64Error::InvalidOffset { offset: 5 })
    );
}

#[test]
fn get_bytes_mut_not_enough_memory() {
    let mut mem = [0u8; 4];
    // offset 2 is valid, but only 2 bytes remain — not enough for N=4
    assert_eq!(
        get_bytes_mut::<4>(&mut mem, 2),
        Err(Rel64Error::NotEnoughMemory { offset: 2 })
    );
}

