// ═══════════════════════════════════════════════════════════════════════
// ld_prel_lo19  (base, target, mem, offset)
//
//   imm19 = (target − place) / 4
//   Signed 19-bit word offset → byte range [−(1<<20), (1<<20)−4]
//   target must be 4-byte aligned relative to place
// ═══════════════════════════════════════════════════════════════════════

#[test]
fn ld_prel_lo19_forward() {
    // place=0;  diff=8;  imm19=2
    let mut mem = insn_buf(LDR_LIT);
    ld_prel_lo19_reloc(0x0, 0x0008, &mut mem, 0).unwrap();
    assert_eq!(dec_imm19(u32_at(&mem, 0)), 2);
}

#[test]
fn ld_prel_lo19_backward() {
    // place=0x100;  diff=−0x100;  imm19=−64
    let mut mem = insn_buf(LDR_LIT);
    ld_prel_lo19_reloc(0x0100, 0x0000, &mut mem, 0).unwrap();
    assert_eq!(dec_imm19(u32_at(&mem, 0)), -64);
}

#[test]
fn ld_prel_lo19_max_positive() {
    // imm19 max = (1<<18)−1 word offsets = 0x3_FFFF → byte diff = 0x0F_FFFC
    let mut mem = insn_buf(LDR_LIT);
    ld_prel_lo19_reloc(0x0, 0x0F_FFFC, &mut mem, 0).unwrap();
    assert_eq!(dec_imm19(u32_at(&mem, 0)), (1 << 18) - 1);
}

#[test]
fn ld_prel_lo19_max_negative() {
    // imm19 min = −(1<<18) word offsets → byte diff = −0x10_0000
    // place=0x10_0000, target=0
    let mut mem = insn_buf(LDR_LIT);
    ld_prel_lo19_reloc(0x10_0000, 0x0, &mut mem, 0).unwrap();
    assert_eq!(dec_imm19(u32_at(&mem, 0)), -(1 << 18));
}

#[test]
fn ld_prel_lo19_overflow_positive() {
    // byte diff = 0x10_0000 → word imm = 1<<18, one above max
    let mut mem = [0u8; 4];
    assert!(matches!(
        ld_prel_lo19_reloc(0x0, 0x10_0000, &mut mem, 0),
        Err(Rel64Error::InvalidBits(BitError::Overflow {
            significant_bits: 19,
            align: 2
        }))
    ));
}

#[test]
fn ld_prel_lo19_overflow_negative() {
    // place=0x10_0004, target=0 → byte diff=−0x10_0004 → one below min
    let mut mem = [0u8; 4];
    assert!(matches!(
        ld_prel_lo19_reloc(0x10_0004, 0x0, &mut mem, 0),
        Err(Rel64Error::InvalidBits(BitError::Overflow {
            significant_bits: 19,
            align: 2
        }))
    ));
}

#[test]
fn ld_prel_lo19_unaligned() {
    let mut mem = [0u8; 4];
    assert!(matches!(
        ld_prel_lo19_reloc(0x0, 0x0002, &mut mem, 0),
        Err(Rel64Error::InvalidBits(BitError::Alignment { align: 2 }))
    ));
}

#[test]
fn ld_prel_lo19_nonzero_offset() {
    // base=0, offset=4 → place=4;  diff=0x10−4=0xC;  imm19=3
    let mut mem = [0u8; 8];
    mem[4..8].copy_from_slice(&LDR_LIT.to_le_bytes());
    ld_prel_lo19_reloc(0x0, 0x10, &mut mem, 4).unwrap();
    assert_eq!(dec_imm19(u32_at(&mem, 4)), 3);
}

