#[test]
fn tst_br14_forward() {
    // place=0x1000;  diff=8;  imm14=2
    let mut mem = insn_buf(TBZ);
    tst_br14_reloc(0x1000, 0x1008, &mut mem, 0).unwrap();
    assert_eq!(dec_imm14(u32_at(&mem, 0)), 2);
}

#[test]
fn tst_br14_backward() {
    // place=0x1008;  diff=−8;  imm14=−2
    let mut mem = insn_buf(TBZ);
    tst_br14_reloc(0x1008, 0x1000, &mut mem, 0).unwrap();
    assert_eq!(dec_imm14(u32_at(&mem, 0)), -2);
}

#[test]
fn tst_br14_max_positive() {
    // imm14 max = (1<<13)−1 = 8191 word offsets → byte diff = 0x7FFC
    let mut mem = insn_buf(TBZ);
    tst_br14_reloc(0x0, 0x7FFC, &mut mem, 0).unwrap();
    assert_eq!(dec_imm14(u32_at(&mem, 0)), (1 << 13) - 1);
}

#[test]
fn tst_br14_max_negative() {
    // imm14 min = −(1<<13) → byte diff = −0x8000;  place=0x8000, target=0
    let mut mem = insn_buf(TBZ);
    tst_br14_reloc(0x8000, 0x0, &mut mem, 0).unwrap();
    assert_eq!(dec_imm14(u32_at(&mem, 0)), -(1 << 13));
}

#[test]
fn tst_br14_overflow_positive() {
    // byte diff=0x8000 → word imm=1<<13, one above max
    let mut mem = [0u8; 4];
    assert!(matches!(
        tst_br14_reloc(0x0, 0x8000, &mut mem, 0),
        Err(Rel64Error::InvalidBits(BitError::Overflow {
            significant_bits: 14,
            align: 2
        }))
    ));
}

#[test]
fn tst_br14_overflow_negative() {
    // place=0x8004, target=0 → byte diff=−0x8004 → one below min
    let mut mem = [0u8; 4];
    assert!(matches!(
        tst_br14_reloc(0x8004, 0x0, &mut mem, 0),
        Err(Rel64Error::InvalidBits(BitError::Overflow {
            significant_bits: 14,
            align: 2
        }))
    ));
}

#[test]
fn tst_br14_unaligned() {
    let mut mem = [0u8; 4];
    assert!(matches!(
        tst_br14_reloc(0x0, 0x2, &mut mem, 0),
        Err(Rel64Error::InvalidBits(BitError::Alignment { align: 2 }))
    ));
}

