// ═══════════════════════════════════════════════════════════════════════
// MOV_W relocations  (target, mem, offset)
//
//   Unsigned Gk: S[k*16+15 : k*16] → imm16
//     Overflow if any bit above chunk k is set (except NC variants).
//   Signed Gk:   same chunk, sign-checked to (k+1)*16 bits.
//     Negative → MOVN with ~chunk; non-negative → MOVZ.
// ═══════════════════════════════════════════════════════════════════════

// ── G0 ───────────────────────────────────────────────────────────────

#[test]
fn mov_w_abs_g0_basic() {
    let mut mem = insn_buf(MOVZ);
    mov_w_abs_g0_reloc(0xABCD, &mut mem, 0).unwrap();
    assert_eq!(dec_movw(u32_at(&mem, 0)), 0xABCD);
}

